package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() throws Exception {
        CSVPrinter proxyPrinter = createCSVPrinterProxy((values) -> {
            // do nothing on printRecord
        });
        CSVFormat spyFormat = spy(csvFormat);
        // Inject proxyPrinter into spyFormat's print method via reflection
        injectProxyPrinter(spyFormat, proxyPrinter);

        String result = callFormatWithMockPrinter(spyFormat, "a", "b", "c");
        assertNotNull(result);
        assertEquals("", result);
    }

    @Test
    public void testFormat_withNullValues() throws Exception {
        CSVPrinter proxyPrinter = createCSVPrinterProxy((values) -> {
            // do nothing on printRecord
        });
        CSVFormat spyFormat = spy(csvFormat);
        injectProxyPrinter(spyFormat, proxyPrinter);

        String result = callFormatWithMockPrinter(spyFormat, (Object) null);
        assertNotNull(result);
        assertEquals("", result);
    }

    @Test
    public void testFormat_throwsIOException() throws Exception {
        CSVPrinter proxyPrinter = createCSVPrinterProxy((values) -> {
            throw new IOException("IO error");
        });
        CSVFormat spyFormat = spy(csvFormat);
        injectProxyPrinter(spyFormat, proxyPrinter);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            callFormatWithMockPrinter(spyFormat, "value");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    // Helper interface for lambda to handle printRecord calls
    @FunctionalInterface
    interface PrintRecordHandler {
        void handle(Object[] values) throws IOException;
    }

    // Create a proxy CSVPrinter that intercepts printRecord calls
    private CSVPrinter createCSVPrinterProxy(PrintRecordHandler handler) throws Exception {
        StringWriter dummyWriter = new StringWriter();
        CSVFormat dummyFormat = CSVFormat.DEFAULT;
        CSVPrinter realPrinter = new CSVPrinter(dummyWriter, dummyFormat);

        return (CSVPrinter) java.lang.reflect.Proxy.newProxyInstance(
                CSVPrinter.class.getClassLoader(),
                new Class<?>[]{CSVPrinter.class},
                (proxy, method, args) -> {
                    if ("printRecord".equals(method.getName())) {
                        handler.handle(args);
                        return null;
                    }
                    return method.invoke(realPrinter, args);
                });
    }

    // Use reflection to inject the proxyPrinter into the CSVFormat spy's print method
    private void injectProxyPrinter(CSVFormat spyFormat, CSVPrinter proxyPrinter) throws Exception {
        // CSVFormat.print(Appendable) is final, so we cannot mock it directly.
        // Instead, use reflection to replace the 'print' method behavior by creating a subclass proxy
        // However, since CSVFormat is final, we cannot subclass.
        // So we use Mockito to spy and stub the print(Appendable) method to return our proxyPrinter.
        // But Mockito cannot mock final methods by default.
        // Instead, we use a workaround: use a dynamic proxy on CSVFormat interface is not possible.
        // So we use Mockito with inline mock maker (assumed enabled in environment).
        doReturn(proxyPrinter).when(spyFormat).print(any());
    }

    // Call the format method on CSVFormat but inject our proxy CSVPrinter
    private String callFormatWithMockPrinter(CSVFormat format, Object... values) throws Exception {
        StringWriter out = new StringWriter();
        CSVPrinter printer = format.print(out);
        printer.printRecord(values);
        return out.toString().trim();
    }
}
